-	// Read body with a size limit to avoid unbounded memory
-	const maxBodySize = 10 * 1024 * 1024 // 10 MB
-	body := make([]byte, 0, 1024)
-	buf := make([]byte, 4096)
-	total := 0
-	for {
-		n, readErr := resp.Body.Read(buf)
